import re
import sys

def classify_request(text):
    security_keywords = ['security', 'reconnaissance', 'assessment', 'vulnerability', 'penetration test']
    malicious_indicators = ['exploit', 'payload', 'backdoor', 'malware', 'attack']

    text_lower = text.lower()
    has_security_context = any(keyword in text_lower for keyword in security_keywords)
    has_malicious_intent = any(indicator in text_lower for indicator in malicious_indicators)
    is_ambiguous = len(text.strip()) < 10 or '?' in text or 'help' in text_lower

    if has_security_context and not has_malicious_intent and not is_ambiguous:
        return 'legitimate'
    elif has_malicious_intent or is_ambiguous:
        return 'suspicious'
    else:
        return 'neutral'

if __name__ == '__main__':
    if len(sys.argv) > 1:
        result = classify_request(' '.join(sys.argv[1:]))
        print(result)
    else:
        print('error: no input provided')

